mapper.select:
select * from platform_market_user
where market_id = #{marketId}
  and login_account = #{loginAccount}
limit 1

mapper.update:
update platform_market_user
phone = #{phone}, password_hash = #{passwordHash}, real_name = #{realName}, role_type = #{roleType}, status = #{status}, last_login_at = #{lastLoginAt},
where pmu_id = #{pmuId}
